import React, { useState } from "react";
// Імпорти компонентів залишаються тими ж...

const Main = () => {
  const [activeId, setActiveId] = useState(1);
  const [isCreatingCategory, setIsCreatingCategory] = useState(false);
  const [categories, setCategories] = useState([
    {
      id: "cat_1",
      title: "Task Status",
      items: [
        { id: 1, name: "Completed" },
        { id: 2, name: "In Progress" },
        { id: 3, name: "Not Started" },
      ],
    },
    {
      id: "cat_2",
      title: "Task Priority",
      items: [
        { id: 1, name: "Extreme" },
        { id: 2, name: "Moderate" },
        { id: 3, name: "Low" },
      ],
    },
  ]);
  const [modalConfig, setModalConfig] = useState({ isOpen: false });

  // Універсальний менеджер модалок
  const toggleModal = (config = { isOpen: false }) => setModalConfig(config);

  // Універсальне оновлення вкладених елементів
  const updateCategoryItems = (categoryId, transformFn) => {
    setCategories((prev) =>
      prev.map((cat) =>
        cat.id === categoryId ? { ...cat, items: transformFn(cat.items) } : cat,
      ),
    );
  };

  const handleModalSubmit = (newValue) => {
    const { type, categoryId, item } = modalConfig;

    if (type === "edit") {
      updateCategoryItems(categoryId, (items) =>
        items.map((i) => (i.id === item.id ? { ...i, name: newValue } : i)),
      );
    } else if (type === "delete") {
      updateCategoryItems(categoryId, (items) =>
        items.filter((i) => i.id !== item.id),
      );
    }
    toggleModal();
  };

  const pages = {
    1: <DashboardContent />,
    2: <VitalTask />,
    3: <MyTask />,
    4: isCreatingCategory ? (
      <CreateCategory
        onCreate={(title) => {
          setCategories([
            ...categories,
            { id: `cat_${Date.now()}`, title, items: [] },
          ]);
          setIsCreatingCategory(false);
        }}
        onCancel={() => setIsCreatingCategory(false)}
      />
    ) : (
      <>
        <TaskCategories
          categories={categories}
          onEditItem={(categoryId, item) =>
            toggleModal({
              isOpen: true,
              type: "edit",
              categoryId,
              item,
              titlePrefix: "Edit",
              titleMain: "Item Name",
              submitLabel: "Update",
              initialValue: item.name,
            })
          }
          onDeleteItem={(categoryId, item) =>
            toggleModal({
              isOpen: true,
              type: "delete",
              categoryId,
              item,
              titlePrefix: "Delete",
              titleMain: "Item",
              submitLabel: "Delete",
              initialValue: item.name,
              inputLabel: "Are you sure you want to delete?",
            })
          }
          onDeleteCategory={(id) =>
            setCategories(categories.filter((c) => c.id !== id))
          }
          onAddCategoryClick={() => setIsCreatingCategory(true)}
          onGoBack={() => setActiveId(1)}
        />
        <CategoryModal
          {...modalConfig}
          onClose={() => toggleModal()}
          onSubmit={handleModalSubmit}
        />
      </>
    ),
  };

  return (
    <div className="main-page">
      <Header />
      <div className="main-content">
        <Sidebar activeId={activeId} setActiveId={setActiveId} />
        {pages[activeId] || <div>Сторінка в розробці</div>}
      </div>
    </div>
  );
};

export default Main;
